import torch, os
src='checkpoints/metricgan_blend00285.pt'
dst='checkpoints/metricgan_blend00283.pt'
alpha=0.0283
ckpt=torch.load(src, map_location='cpu')

def upd(obj):
    if isinstance(obj, dict):
        for k,v in list(obj.items()):
            lk=str(k).lower()
            if isinstance(v, (float,int)) and any(s in lk for s in ['blend','mix','alpha','noisy_weight','noise_weight']):
                obj[k]=alpha
            else:
                upd(v)
    elif isinstance(obj, list):
        for v in obj: upd(v)
upd(ckpt)
# common top-level names used by predict.py variants
for k in ['blend_noisy','noisy_blend','blend_alpha','alpha','mix_noisy','noisy_mix','noisy_weight']:
    if isinstance(ckpt, dict) and (k in ckpt or 'blend' in k or 'alpha' in k):
        ckpt[k]=alpha
# preserve explicit mode if present or infer blend mode
if isinstance(ckpt, dict):
    ckpt.setdefault('mode','metricgan')
    ckpt['blend_noisy']=alpha
    ckpt['noisy_blend']=alpha
os.makedirs(os.path.dirname(dst), exist_ok=True)
torch.save(ckpt, dst)
PY
